const prices = [10, 25, 50, 100, 5];

// filter: keep items under $30
let affordable = prices.filter(p => p < 30);
console.log(affordable);
// Expected output: [10, 25, 5]

// map: add 10% tax to each price
let withTax = prices.map(p => p * 1.1);
console.log(withTax);
// Expected output: [11, 27.5, 55, 110, 5.5]

// reduce: calculate total
let total = prices.reduce((sum, p) => sum + p, 0);
console.log(total);
// Expected output: 190

// Chain methods
let result = prices
  .filter(p => p > 20)
  .map(p => p * 1.1)
  .reduce((sum, p) => sum + p, 0);
console.log(result);
// Expected output: 192.5
